import{_ as a,c as e,o,ag as p}from"./chunks/framework.ELrfyV9R.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/aehyok/status/2043898520395247794","created":"2026-04-14T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/想使用Claude的朋友们，可以来看看这个IP 风险检测网站辅助工具.md","filePath":"ai/bookmark/想使用Claude的朋友们，可以来看看这个IP 风险检测网站辅助工具.md","lastUpdated":1776858534000}'),r={name:"ai/bookmark/想使用Claude的朋友们，可以来看看这个IP 风险检测网站辅助工具.md"};function m(s,t,_,l,i,c){return o(),e("div",null,t[0]||(t[0]=[p('<p><img src="https://pbs.twimg.com/media/HF1hyawasAQJhle?format=jpg&amp;name=large" alt="图像"></p><p>早上看到不滑锅发的一个短贴蛮有意思，于是自己尝试了一下，把风险降低到了5%，理论上风险应该是0了。应该说是可以来参考降低风险，并不是说做到100%就万事大吉了。</p><p>首先打开这个网站 <a href="https://cc.mastersgo.cc/" target="_blank" rel="noreferrer">https://cc.mastersgo.cc</a>，看这就是下面我优化完的结果了。</p><p>我优化完已经达到只有5%的风险了，去看风险第三张图，其实我也能够访问Claude的，所以这个作为一个参考，还是非常不错的。</p><p><img src="https://pbs.twimg.com/media/HF1YY1RacAAXkR2?format=jpg&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HF1YQsYasAMemzL?format=jpg&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HF1Y8LqboAAtATT?format=jpg&amp;name=large" alt="图像"></p><p>针对我的电脑我主要优化了以下几个事项：</p><ul><li>1、静态住宅IP最好是要要的，稳定性就很强了</li><li>2、设置了我的mac电脑系统时区为北美太平洋夏季时间</li><li>3、Chrome浏览器设置Location-&gt;右上角三个点-&gt;更多工具-&gt;开发者工具-&gt;Command(ctrl) +Shift +P-&gt; Show Sensors-&gt; Location-&gt; 选择一个美国的地点，或者自己单独添加合适的定位</li><li>4、下载Chrome扩展禁用WebRTC来防止真实IP地址泄漏：<strong>WebRTC Leak Prevent</strong></li><li>5、浏览器设置定位尽量与电脑时区和静态住宅IP地址保持相对一致</li></ul><p>暂时就想到这么多分享一下,最后想要注册账号的可以参考一下我刚写的文章</p><blockquote><p>4月13日</p></blockquote>',11)]))}const d=a(r,[["render",m]]);export{g as __pageData,d as default};
